B.Zb=new A.E("When you send a message, stream a video, or load a webpage, your device breaks the data into tiny pieces called packets. Each packet contains part of the data plus information about where it\u2019s going and how to reassemble it when it arrives.",null,null,null,null,null,null,null,null)
B.Yp=new A.E("Sending & Receiving",null,B.y,null,null,null,null,null,null)
B.a_o=new A.E("Packets travel across networks through routers and switches. They may take different paths and arrive at different times, but your device reassembles them into the original message.",null,null,null,null,null,null,null,null)
B.a_j=new A.E("Why This Matters for Security",null,B.y,null,null,null,null,null,null)
B.a_i=new A.E("Attackers can intercept or modify packets on unsecured networks. This is why HTTPS and encryption are essential \u2014 they protect packets from being read or changed.",null,null,null,null,null,null,null,null)
