B.a_w=new A.E("The Internet: A Giant Postal and Road System Combined",null,B.y,null,null,null,null,null,null)
B.a_t=new A.E("When you load a webpage, your device sends tiny packets \u2014 digital envelopes \u2014 across a massive global network. These packets travel through your router, your internet provider, regional networks, and undersea cables before reaching the destination server.",null,null,null,null,null,null,null,null)
B.Ys=new A.E("DNS: Turning Names Into Addresses (The Internet\u2019s GPS)",null,B.y,null,null,null,null,null,null)
B.a_r=new A.E("When you type a website name like amazon.com, your device doesn\u2019t know where that is. DNS translates the name into an IP address \u2014 the real location of the server. Without DNS, you\u2019d have to memorize IP addresses for every site you visit.",null,null,null,null,null,null,null,null)
B.XM=new A.E("Routing: How Packets Choose a Path Across the World",null,B.y,null,null,null,null,null,null)
B.Zk=new A.E("Packets may travel through dozens of routers before reaching their destination. Each router chooses the fastest or least congested path. Packets can take different routes and arrive out of order, but your device reassembles them into the original message.",null,null,null,null,null,null,null,null)
B.a_f=new A.E("HTTPS: Encryption That Protects You on the Move",null,B.y,null,null,null,null,null,null)
B.Y4=new A.E("HTTPS encrypts your data so attackers cannot read it, even if they intercept the packets. Without HTTPS, anyone on the same Wi\u2011Fi \u2014 like at a coffee shop \u2014 could see your passwords, messages, or personal information.\n\nUnderstanding how the internet moves data helps students see where attacks can happen \u2014 and how encryption defends against them.",null,null,null,null,null,null,null,null)
